import os
import numpy as np

working_dir = os.path.join(os.getcwd(), "working")
experiment_path = os.path.join(working_dir, "experiment_data.npy")

experiment_data = np.load(experiment_path, allow_pickle=True).item()


def safe_float(value):
    try:
        return float(value)
    except Exception:
        return value


def print_epoch_metric_summary(
    dataset_name, metric_entries, value_key, metric_label, mode="final", best_mode=None
):
    if not metric_entries:
        return

    valid_entries = [
        entry
        for entry in metric_entries
        if isinstance(entry, dict) and value_key in entry
    ]
    if not valid_entries:
        return

    if mode == "final":
        final_entry = valid_entries[-1]
        print(f"Dataset: {dataset_name}")
        print(f"{metric_label}: {safe_float(final_entry[value_key]):.6f}")

    if best_mode == "max":
        best_entry = max(valid_entries, key=lambda x: x[value_key])
        print(f"Dataset: {dataset_name}")
        print(f"best {metric_label}: {safe_float(best_entry[value_key]):.6f}")
    elif best_mode == "min":
        best_entry = min(valid_entries, key=lambda x: x[value_key])
        print(f"Dataset: {dataset_name}")
        print(f"best {metric_label}: {safe_float(best_entry[value_key]):.6f}")


def print_stream_metrics(dataset_name, stream_entries):
    if not stream_entries:
        return

    final_stream_entry = stream_entries[-1]
    if not isinstance(final_stream_entry, dict):
        return

    print(f"Dataset: {dataset_name}")
    for key, value in final_stream_entry.items():
        readable_name = key.replace("_", " ")
        print(f"final {readable_name}: {safe_float(value):.6f}")


def print_per_strategy_metrics(dataset_name, per_strategy):
    if not isinstance(per_strategy, dict):
        return

    for strategy_name, strategy_data in per_strategy.items():
        if not isinstance(strategy_data, dict):
            continue

        metrics = strategy_data.get("metrics", {})
        if isinstance(metrics, dict) and "stream_acc" in metrics:
            print(f"Dataset: {dataset_name}")
            print(
                f"{strategy_name} stream accuracy: {safe_float(metrics['stream_acc']):.6f}"
            )

        losses = strategy_data.get("losses", None)
        if losses is not None:
            losses_arr = np.asarray(losses)
            if losses_arr.size > 0:
                print(f"Dataset: {dataset_name}")
                print(
                    f"{strategy_name} final batch adaptation loss: {safe_float(losses_arr[-1]):.6f}"
                )

        cumulative_acc = strategy_data.get("cumulative_acc", None)
        if cumulative_acc is not None:
            cumulative_acc_arr = np.asarray(cumulative_acc)
            if cumulative_acc_arr.size > 0:
                print(f"Dataset: {dataset_name}")
                print(
                    f"{strategy_name} final cumulative stream accuracy: {safe_float(cumulative_acc_arr[-1]):.6f}"
                )


for dataset_name, dataset_data in experiment_data.items():
    if not isinstance(dataset_data, dict):
        continue

    metrics = dataset_data.get("metrics", {})
    losses = dataset_data.get("losses", {})
    per_strategy = dataset_data.get("per_strategy", {})

    train_metric_entries = metrics.get("train", []) if isinstance(metrics, dict) else []
    val_metric_entries = metrics.get("val", []) if isinstance(metrics, dict) else []
    stream_metric_entries = (
        metrics.get("stream", []) if isinstance(metrics, dict) else []
    )

    train_loss_entries = losses.get("train", []) if isinstance(losses, dict) else []
    val_loss_entries = losses.get("val", []) if isinstance(losses, dict) else []

    print_epoch_metric_summary(
        dataset_name=dataset_name,
        metric_entries=train_metric_entries,
        value_key="acc",
        metric_label="final train accuracy",
        mode="final",
    )
    print_epoch_metric_summary(
        dataset_name=dataset_name,
        metric_entries=val_metric_entries,
        value_key="acc",
        metric_label="final validation accuracy",
        mode="final",
    )
    print_epoch_metric_summary(
        dataset_name=dataset_name,
        metric_entries=train_loss_entries,
        value_key="loss",
        metric_label="best train loss",
        best_mode="min",
    )
    print_epoch_metric_summary(
        dataset_name=dataset_name,
        metric_entries=val_loss_entries,
        value_key="loss",
        metric_label="best validation loss",
        best_mode="min",
    )

    print_stream_metrics(dataset_name, stream_metric_entries)
    print_per_strategy_metrics(dataset_name, per_strategy)

